// Flat coefficient buffer shared by jet (stride 9) and Möbius-c+ (stride 5,
// order A, B, A', D, D') — exclusive modes, identical 12 B element.
const JET_COEFF_STRIDE: i32 = 9;
const MOBIUS_COEFF_STRIDE: i32 = 5;
